def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        oscillation = 0
        if ratio > 10:
            for a in range(10, 4, -2):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / (a * b * 1.1 + 1)
                    priority += val * np.sin(ratio * b / (a + 2)) * np.exp(-b / (a + 5))
                priority += np.tanh(ratio - a) * 7
            priority += (np.exp(ratio - 9) * np.cos(ratio * 1.3)) ** 1.8
        elif 6 < ratio <= 10:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 0.9) / (q + 0.7)
                    priority += np.tanh(term) * 1.8
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.2
        elif 3 <= ratio <= 6:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r * 1.5) * np.sin(r * ratio * 1.2)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (6 - ratio)) * 1.9
        elif 1.2 <= ratio < 3:
            s = 0
            for n in range(1, 14):
                s += ((3 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3.1
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.08))
            for m in range(1, 6):
                oscillation += np.cos(m * ratio * i) * ((ratio - 1.2) ** m) / (m ** 1.1)
            priority += oscillation
        elif 0.5 <= ratio < 1.2:
            s = 0
            for n in range(1, 18):
                s += ((1.2 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 2.5)
            for j in range(1, 7):
                priority += ((1.2 - ratio) ** j) * np.cos(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.sin(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.6) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.6) * 4.2
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.4)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.0)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.85) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if i % 2 == 0:
            priority += np.tanh(ratio * i) * 0.5
        if int(item + bin_cap) % 3 == 0:
            priority += np.log1p(ratio + i) * 0.8
        else:
            priority -= np.sqrt(np.abs(ratio - i)) * 0.8
        if bin_cap != 0:
            for z in range(1, 4):
                priority += (np.sin(item * z) * np.cos(bin_cap / (z + 1))) / (z + 0.5)
        priorities[i] = priority
    return priorities
